 1	import React, { FC } from 'react';
 2	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
 3	
 4	import { Checkbox, CheckboxProps, Flex, FlexItem, Popover } from '@patternfly/react-core';
 5	import { HelpIcon } from '@patternfly/react-icons';
 6	
 7	type ApplySelectorCheckboxProps = {
 8	  isChecked: boolean;
 9	  onChange: CheckboxProps['onChange'];
10	};
11	
12	const ApplySelectorCheckbox: FC<ApplySelectorCheckboxProps> = ({ isChecked, onChange }) => {
13	  const { t } = useNMStateTranslation();
14	  return (
15	    <Flex flexWrap={{ default: 'nowrap' }} spacer={{ default: 'spacerNone' }}>
16	      <FlexItem spacer={{ default: 'spacerNone' }}>
17	        <Checkbox
18	          id="apply-nncp-selector"
19	          isChecked={isChecked}
20	          onChange={onChange}
21	          label={t(
22	            'Apply this NodeNetworkConfigurationPolicy only to specific subsets of nodes using the node selector',
23	          )}
24	        />
25	      </FlexItem>
26	      <FlexItem>
27	        <Popover
28	          bodyContent={t(
29	            'Deselect this box to apply the policy to all matching nodes on the cluster',
30	          )}
31	        >
32	          <HelpIcon />
33	        </Popover>
34	      </FlexItem>
35	    </Flex>
36	  );
37	};
38	
39	export default ApplySelectorCheckbox;

